{
var text = GetString(parameters, "text", "Hello");
var fgColor = GetColor(parameters, "fontColor", System.Windows.Media.Color.FromRgb(255, 255, 255));
var bgColor = GetColor(parameters, "bgColor", System.Windows.Media.Color.FromRgb(0, 0, 0));
var fontSize = Math.Max(4f, GetFloat(parameters, "fontSize", 20f));
var showBg = GetBool(parameters, "showBg", false);
var border = Math.Max(0f, GetFloat(parameters, "border", 4f));
var size = context.TileSize;
var result = new PixelBuffer(size, size);
// Use WPF to render text into a bitmap
System.Windows.Media.DrawingVisual dv = null;
System.Windows.Media.Imaging.RenderTargetBitmap rtb = null;
try
{
    dv = new System.Windows.Media.DrawingVisual();
    using (var dc = dv.RenderOpen())
    {
        if (showBg)
            dc.DrawRectangle(new System.Windows.Media.SolidColorBrush(bgColor), null, new System.Windows.Rect(0, 0, size, size));
        var tf = new System.Windows.Media.FormattedText(
            string.IsNullOrEmpty(text) ? " " : text,
            System.Globalization.CultureInfo.CurrentCulture,
            System.Windows.FlowDirection.LeftToRight,
            new System.Windows.Media.Typeface("Segoe UI"),
            fontSize,
            new System.Windows.Media.SolidColorBrush(fgColor),
            96);
        var tx = Math.Max(border, (size - tf.Width) * 0.5);
        var ty = Math.Max(border, (size - tf.Height) * 0.5);
        dc.DrawText(tf, new System.Windows.Point(tx, ty));
    }
    rtb = new System.Windows.Media.Imaging.RenderTargetBitmap(size, size, 96, 96, System.Windows.Media.PixelFormats.Pbgra32);
    rtb.Render(dv);
    var stride = size * 4;
    var pixels = new byte[size * stride];
    rtb.CopyPixels(pixels, stride, 0);
    result.ParallelForEachPixel((x, y) =>
    {
        var i = (y * size + x) * 4;
        var b = pixels[i] / 255f;
        var g = pixels[i+1] / 255f;
        var r = pixels[i+2] / 255f;
        var a = pixels[i+3] / 255f;
        result.SetPixel(x, y, r, g, b, a);
    });
}
catch { }
return result;
}
